using System;
using System.Collections.Generic;

namespace Unterrichtscode
{
    internal class Program
    {
        private static void Main(string[] args)
        {
            Queue<int> paketWarteschlange = new Queue<int>();
            paketWarteschlange.Enqueue(201);
            paketWarteschlange.Enqueue(303);
            paketWarteschlange.Enqueue(204);
            paketWarteschlange.Enqueue(303);
            paketWarteschlange.Enqueue(406);
            paketWarteschlange.Enqueue(507);

            HashSet<int> eindeutigePakete = new HashSet<int>(paketWarteschlange);
            Console.WriteLine($"Anzahl einzigartiger Pakete im System: {eindeutigePakete.Count}\n");

            Stack<int> rueckgabeStapel = new Stack<int>();

            Console.WriteLine("--- Verarbeitungs-Prozess startet ---");
            while (paketWarteschlange.Count > 0)
            {
                int aktuellesPaket = paketWarteschlange.Dequeue();

                if (aktuellesPaket % 2 == 0)
                {
                    Console.WriteLine($"Paket {aktuellesPaket} ist beschädigt -> Auf Stapel gelegt.");
                    rueckgabeStapel.Push(aktuellesPaket);
                }
                else
                {
                    Console.WriteLine($"Paket {aktuellesPaket} erfolgreich verarbeitet.");
                }
            }

            Console.WriteLine("\n--- Rückgabe-Stapel wird rückwärts ausgepackt (LIFO) ---");
            while (rueckgabeStapel.Count > 0)
            {
                int zurueckgegebenesPacket = rueckgabeStapel.Pop();
                Console.WriteLine($"Rückabwicklung von Paket: {zurueckgegebenesPacket}");
            }
        }
    }
}

using System;
using System.Collections.Generic;

namespace Unterrichtscode
{
    internal class Program
    {
        private static void Main(string[] args)
        {
            Queue<string> druckWarteschlange = new Queue<string>();
            druckWarteschlange.Enqueue("Bericht.pdf");
            druckWarteschlange.Enqueue("Rechnung.pdf");
            druckWarteschlange.Enqueue("Präsentation.pptx");
            druckWarteschlange.Enqueue("Rechnung.pdf");
            druckWarteschlange.Enqueue("Skript.docx");

            HashSet<string> eindeutigeDokumente = new HashSet<string>(druckWarteschlange);
            Console.WriteLine($"Anzahl einzigartiger Dokumente in der Warteschlange: {eindeutigeDokumente.Count}\n");

            Stack<string> fehlerStapel = new Stack<string>();

            Console.WriteLine("--- Druckvorgang gestartet ---");
            while (druckWarteschlange.Count > 0)
            {
                string aktuellesDokument = druckWarteschlange.Dequeue();

                if (aktuellesDokument.EndsWith(".pdf"))
                {
                    Console.WriteLine($"Drucke Dokument: {aktuellesDokument}");
                }
                else
                {
                    Console.WriteLine($"FEHLER: {aktuellesDokument} kann nicht gedruckt werden -> Auf Fehlerstapel verschoben.");
                    fehlerStapel.Push(aktuellesDokument);
                }
            }

            Console.WriteLine("\n--- Nicht gedruckte Dokumente (Neueste zuerst) ---");
            while (fehlerStapel.Count > 0)
            {
                string fehlerhafteDatei = fehlerStapel.Pop();
                Console.WriteLine($"Admin-Hinweis: Fehler bei Datei: {fehlerhafteDatei}");
            }
        }
    }
}

using System;
using System.Collections.Generic;

namespace Unterrichtscode
{
    internal class Program
    {
        private static void Main(string[] args)
        {
            List<int> warenkorb = new List<int>();
            warenkorb.Add(1001);
            warenkorb.Add(1002);
            warenkorb.Add(1001);
            warenkorb.Add(1003);
            warenkorb.Add(1002);
            warenkorb.Add(1004);

            HashSet<int> eindeutigeProdukte = new HashSet<int>(warenkorb);

            Dictionary<int, string> kategorien = new Dictionary<int, string>();
            kategorien[1001] = "Elektronik";
            kategorien[1002] = "Lebensmittel";
            kategorien[1003] = "Kleidung";
            kategorien[1004] = "Elektronik";

            Console.WriteLine("--- Warenkorb-Analyse ---");
            Console.WriteLine($"Gesamtanzahl Artikel im Warenkorb: {warenkorb.Count}");
            Console.WriteLine($"Anzahl verschiedener Produkte: {eindeutigeProdukte.Count}\n");

            Console.WriteLine("--- Punkteberechnung ---");
            int gesamtPunkte = BerechnePunkte(warenkorb, kategorien);
            Console.WriteLine($"\nEndstand Treuepunkte: {gesamtPunkte}");
        }

        static int BerechnePunkte(List<int> warenkorb, Dictionary<int, string> kategorien)
        {
            int gesamtPunkte = 0;
            foreach (int artikelId in warenkorb)
            {
                if (!kategorien.ContainsKey(artikelId)) continue;

                string kategorie = kategorien[artikelId];
                int punkte = 0;

                if (kategorie == "Elektronik") punkte = 10;
                else if (kategorie == "Lebensmittel") punkte = 2;
                else punkte = 5;

                Console.WriteLine($"Artikel {artikelId} ({kategorie}) gescannt: +{punkte} Punkte");
                gesamtPunkte += punkte;
            }
            return gesamtPunkte;
        }
    }
}

using System;
using System.Collections.Generic;

namespace Unterrichtscode
{
    internal class Program
    {
        private static void Main(string[] args)
        {
            List<string> rueckgaben = new List<string>();
            rueckgaben.Add("978-3-12-732320-7");
            rueckgaben.Add("000-INVALID");
            rueckgaben.Add("978-3-12-732320-7");
            rueckgaben.Add("978-0-06-112008-4");
            rueckgaben.Add("ABC-FALSCH");
            rueckgaben.Add("978-0-7432-7356-5");

            HashSet<string> eindeutigeISBNs = new HashSet<string>(rueckgaben);
            Console.WriteLine($"Eindeutige ISBNs in der Rückgabe: {eindeutigeISBNs.Count}\n");

            Dictionary<string, int> rueckgabeHaeufigkeit = new Dictionary<string, int>();
            Stack<string> fehlerStapel = new Stack<string>();

            Console.WriteLine("--- Rückgabeprozess ---");
            foreach (string isbn in rueckgaben)
            {
                if (isbn.StartsWith("978"))
                {
                    Console.WriteLine($"ISBN {isbn} erfolgreich zurückgenommen.");
                    if (rueckgabeHaeufigkeit.ContainsKey(isbn))
                        rueckgabeHaeufigkeit[isbn]++;
                    else
                        rueckgabeHaeufigkeit[isbn] = 1;
                }
                else
                {
                    Console.WriteLine($"ISBN {isbn} -> Auf Fehlerstapel.");
                    fehlerStapel.Push(isbn);
                }
            }

            Console.WriteLine("\n--- Rückgabe-Häufigkeit ---");
            foreach (KeyValuePair<string, int> eintrag in rueckgabeHaeufigkeit)
                Console.WriteLine($"{eintrag.Key}: {eintrag.Value}x zurückgegeben");

            Console.WriteLine("\n--- Fehlerhafte ISBNs (LIFO) ---");
            while (fehlerStapel.Count > 0)
                Console.WriteLine($"Ungültig: {fehlerStapel.Pop()}");
        }
    }
}

using System;
using System.Collections.Generic;

namespace Unterrichtscode
{
    internal class Program
    {
        private static void Main(string[] args)
        {
            List<string> aufgaben = new List<string>();
            aufgaben.Add("Report erstellen");
            aufgaben.Add("DRINGEND: Server neustart");
            aufgaben.Add("Meeting vorbereiten");
            aufgaben.Add("DRINGEND: Backup prüfen");
            aufgaben.Add("E-Mails beantworten");

            Stack<string> prioritaetsStapel = new Stack<string>();
            Queue<string> normaleWarteschlange = new Queue<string>();

            foreach (string aufgabe in aufgaben)
            {
                if (aufgabe.StartsWith("DRINGEND:"))
                    prioritaetsStapel.Push(aufgabe);
                else
                    normaleWarteschlange.Enqueue(aufgabe);
            }

            ZusammenfassungAusgeben(prioritaetsStapel, normaleWarteschlange);
        }

        static void ZusammenfassungAusgeben(Stack<string> prioritaet, Queue<string> normal)
        {
            Console.WriteLine("--- Dringende Aufgaben (LIFO) ---");
            while (prioritaet.Count > 0)
            {
                Console.WriteLine($"Vorschau: {prioritaet.Peek()}");
                Console.WriteLine($"Erledigt: {prioritaet.Pop()}\n");
            }

            Console.WriteLine("--- Normale Aufgaben (FIFO) ---");
            while (normal.Count > 0)
                Console.WriteLine($"Aufgabe: {normal.Dequeue()}");
        }
    }
}

using System;
using System.Collections.Generic;

namespace Unterrichtscode
{
    internal class Program
    {
        private static void Main(string[] args)
        {
            Dictionary<string, Dictionary<string, string>> dictionary =
                new Dictionary<string, Dictionary<string, string>>();

            AddWordTranslation(dictionary, "Hallo", "EN", "Hello");
            AddWordTranslation(dictionary, "Hallo", "HU", "Szia");
            AddWordTranslation(dictionary, "Hallo", "SK", "Dobrý deň");

            DisplayAllTranslations(dictionary);

            UpdateWordTranslation(dictionary, "Hallo", "EN", "Hi");

            Console.WriteLine("Hallo in HU = {0} ", GetWordTranslation(dictionary, "Hallo", "HU"));
            Console.WriteLine("Hallo in SK = {0}", GetWordTranslation(dictionary, "Hallo", "SK"));
            Console.WriteLine("Hallo in HR = {0}", GetWordTranslation(dictionary, "Hallo", "HR"));

            DisplayAllTranslations(dictionary);
        }

        static void AddWordTranslation(Dictionary<string, Dictionary<string, string>> dict, string wort, string sprache, string uebersetzung)
        {
            if (!dict.ContainsKey(wort))
                dict[wort] = new Dictionary<string, string>();
            dict[wort][sprache] = uebersetzung;
        }

        static void UpdateWordTranslation(Dictionary<string, Dictionary<string, string>> dict, string wort, string sprache, string neueUebersetzung)
        {
            if (dict.ContainsKey(wort) && dict[wort].ContainsKey(sprache))
                dict[wort][sprache] = neueUebersetzung;
        }

        static string GetWordTranslation(Dictionary<string, Dictionary<string, string>> dict, string wort, string sprache)
        {
            if (dict.ContainsKey(wort) && dict[wort].ContainsKey(sprache))
                return dict[wort][sprache];
            return "*Wort im Wörterbuch nicht vorhanden*";
        }

        static void DisplayAllTranslations(Dictionary<string, Dictionary<string, string>> dict)
        {
            foreach (var eintrag in dict)
            {
                Console.Write($"{eintrag.Key}: ");
                foreach (var uebersetzung in eintrag.Value)
                    Console.Write($"[{uebersetzung.Key}: {uebersetzung.Value}] ");
                Console.WriteLine();
            }
        }
    }
}
